// Get HTML from previous HTTP Request node
const html = $json.body;

// Regex to capture all data-inject attributes
const regex = /data-inject\s*=\s*["']([^"']+)["']/g;
let match;
const injectKeys = [];

while ((match = regex.exec(html)) !== null) {
  injectKeys.push(match[1]);
}

// Remove duplicates
const uniqueInjects = [...new Set(injectKeys)];

// Return results
return [{
  json: {
    total_found: uniqueInjects.length,
    data_injects: uniqueInjects
  }
}];
